#pragma once

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp8.h>
#include <stdint.h>
#include <torch/extension.h>

// Constants from specification
constexpr int NUM_INDEX_HEADS = 64;
constexpr int INDEX_HEAD_DIM = 128;
constexpr int PAGE_SIZE = 64;
constexpr int TOPK = 2048;
constexpr int KV_CACHE_NUM_HEADS = 1;
constexpr int HEAD_DIM_WITH_SCALE = 132;
constexpr int HEAD_DIM = 128;

// FP8 format type
typedef __nv_fp8_e4m3 FP8;

// Kernel launch configuration
constexpr int BLOCK_SIZE = 256;
constexpr int WARPS_PER_BLOCK = 8;
constexpr int THREADS_PER_WARP = 32;

// Device function declarations
__device__ __forceinline__ float dequant_fp8_byte(uint8_t byte_val);
__device__ __forceinline__ float load_scale(const uint8_t* k_cache, int page_idx, int token_offset);
__device__ __forceinline__ void load_k_for_token(const uint8_t* k_cache, int page_idx, int token_offset, float* k_vals);

// Kernel launch configuration
__global__ void dsa_topk_indexer_kernel(
    const uint8_t* q_index_fp8,
    const uint8_t* k_index_cache_fp8,
    const float* weights,
    const int* seq_lens,
    const int* block_table,
    int* topk_indices,
    int batch_size,
    int num_pages,
    int max_num_pages
);

// Host function declarations
void launch_dsa_topk_indexer(
    const uint8_t* q_index_fp8,
    const uint8_t* k_index_cache_fp8,
    const float* weights,
    const int* seq_lens,
    const int* block_table,
    int* topk_indices,
    int batch_size,
    int num_pages,
    int max_num_pages,
    cudaStream_t stream = 0
);

// PyTorch binding function
std::tuple<torch::Tensor> run(
    torch::Tensor q_index_fp8,
    torch::Tensor k_index_cache_fp8,
    torch::Tensor weights,
    torch::Tensor seq_lens,
    torch::Tensor block_table
);

#include "kernel.h"
#include <device_launch_parameters.h>
#include <limits>
#include <algorithm>

// FP8 E4M3 to float32 conversion using bit manipulation
__device__ __forceinline__ float dequant_fp8_byte(uint8_t byte_val) {
    uint32_t val = byte_val;

    uint32_t sign = (val >> 7) & 0x1;
    uint32_t exponent = (val >> 3) & 0xF;
    uint32_t mantissa = val & 0x7;

    float result;

    if (exponent == 0) {
        if (mantissa == 0) {
            result = sign ? -0.0f : 0.0f;
        } else {
            // Subnormal
            float mantissa_val = 0.125f * static_cast<float>(mantissa);
            result = (sign ? -1.0f : 1.0f) * mantissa_val * 0.015625f;
        }
    } else if (exponent == 15) {
        if (mantissa == 0) {
            result = sign ? -INFINITY : INFINITY;
        } else {
            result = NAN;
        }
    } else {
        // Normal
        int exp_int = static_cast<int>(exponent) - 7;
        float exp_val = ldexpf(1.0f, exp_int);
        float mantissa_val = 1.0f + 0.125f * static_cast<float>(mantissa);
        result = (sign ? -1.0f : 1.0f) * mantissa_val * exp_val;
    }

    return result;
}

__device__ __forceinline__ float load_scale(const uint8_t* k_cache, int page_idx, int token_offset) {
    // Memory layout per page: [fp8_data (page_size * 128 bytes), scales (page_size * 4 bytes)]
    // Scales are stored at the END of each page, NOT interleaved with FP8 data
    int fp8_data_size = PAGE_SIZE * HEAD_DIM;  // 64 * 128 = 8192 bytes
    int scale_start = page_idx * (fp8_data_size + PAGE_SIZE * 4);  // Start of scales for this page

    int scale_offset = scale_start + token_offset * 4;

    uint32_t scale_int = 0;
    scale_int |= static_cast<uint32_t>(k_cache[scale_offset]) << 0;
    scale_int |= static_cast<uint32_t>(k_cache[scale_offset + 1]) << 8;
    scale_int |= static_cast<uint32_t>(k_cache[scale_offset + 2]) << 16;
    scale_int |= static_cast<uint32_t>(k_cache[scale_offset + 3]) << 24;

    float scale = 0.0f;
    *reinterpret_cast<uint32_t*>(&scale) = scale_int;

    return scale;
}

__device__ __forceinline__ void load_k_for_token(const uint8_t* k_cache, int page_idx, int token_offset, float* k_vals) {
    // FP8 data starts at page_idx * (PAGE_SIZE * HEAD_DIM)
    int fp8_data_size = PAGE_SIZE * HEAD_DIM;
    int fp8_start = page_idx * fp8_data_size;
    int fp8_offset = fp8_start + token_offset * HEAD_DIM;

    float scale = load_scale(k_cache, page_idx, token_offset);

    for (int d = 0; d < INDEX_HEAD_DIM; d++) {
        float fp8_val = dequant_fp8_byte(k_cache[fp8_offset + d]);
        k_vals[d] = fp8_val * scale;
    }
}

__global__ void dsa_topk_indexer_kernel(
    const uint8_t* q_index_fp8,
    const uint8_t* k_index_cache_fp8,
    const float* weights,
    const int* seq_lens,
    const int* block_table,
    int* topk_indices,
    int batch_size,
    int num_pages,
    int max_num_pages
) {
    int b = blockIdx.x;
    int tid = threadIdx.x;

    if (b >= batch_size) return;

    int seq_len = seq_lens[b];

    // Initialize output with -1
    for (int i = tid; i < TOPK; i += BLOCK_SIZE) {
        topk_indices[b * TOPK + i] = -1;
    }

    if (seq_len == 0) return;

    // Calculate number of pages for this sequence
    int num_pages_for_seq = (seq_len + PAGE_SIZE - 1) / PAGE_SIZE;

    // Load Q data for this batch element
    const uint8_t* q_ptr = q_index_fp8 + b * NUM_INDEX_HEADS * INDEX_HEAD_DIM;

    // Load weights for this batch element
    const float* w_ptr = weights + b * NUM_INDEX_HEADS;

    // Load block table for this sequence
    const int* block_ptr = block_table + b * max_num_pages;

    // Use shared memory for scores (up to seq_len)
    extern __shared__ char shared_mem[];
    float* scores = reinterpret_cast<float*>(shared_mem);

    // Initialize scores to 0
    for (int i = tid; i < seq_len; i += BLOCK_SIZE) {
        scores[i] = 0.0f;
    }
    __syncthreads();

    // Process each index head
    for (int h = 0; h < NUM_INDEX_HEADS; h++) {
        // Load Q for this head
        const uint8_t* q_head_ptr = q_ptr + h * INDEX_HEAD_DIM;
        float q_vals[INDEX_HEAD_DIM];
        for (int d = 0; d < INDEX_HEAD_DIM; d++) {
            q_vals[d] = dequant_fp8_byte(q_head_ptr[d]);
        }

        // Process all tokens in sequence
        int token_idx = 0;
        for (int p = 0; p < num_pages_for_seq; p++) {
            int page_idx = block_ptr[p];
            int tokens_in_page = min(PAGE_SIZE, seq_len - token_idx);

            for (int t = 0; t < tokens_in_page; t++) {
                int local_token_idx = token_idx + t;

                // Load K for this token
                float k_vals[INDEX_HEAD_DIM];
                load_k_for_token(k_index_cache_fp8, page_idx, t, k_vals);

                // Compute dot product Q @ K
                float score = 0.0f;
                for (int d = 0; d < INDEX_HEAD_DIM; d++) {
                    score += q_vals[d] * k_vals[d];
                }

                // Apply ReLU and weight
                float weighted_score = fmaxf(0.0f, score) * w_ptr[h];

                // Accumulate score
                scores[local_token_idx] += weighted_score;
            }

            token_idx += tokens_in_page;
        }
    }
    __syncthreads();

    // Select top-K using atomic operations for thread safety
    int actual_topk = min(TOPK, seq_len);

    // Each thread maintains its own local top-k candidates
    __shared__ float shared_topk_vals[TOPK];
    __shared__ int shared_topk_idx[TOPK];

    // Initialize shared top-k with minimum values (only thread 0)
    if (tid == 0) {
        for (int i = 0; i < actual_topk; i++) {
            shared_topk_vals[i] = -std::numeric_limits<float>::infinity();
            shared_topk_idx[i] = -1;
        }
    }
    __syncthreads();

    // Each thread processes its portion of scores and maintains local top-k
    // Then we use atomic operations to update shared top-k
    for (int i = tid; i < seq_len; i += BLOCK_SIZE) {
        float score = scores[i];

        // Find position to insert in shared top-k (thread-safe with atomics)
        for (int k = 0; k < actual_topk; k++) {
            float shared_val = __ldg(&shared_topk_vals[k]);
            if (score > shared_val) {
                // Try to atomically update
                float old_val = atomicMax(&shared_topk_vals[k], score);
                if (score > old_val) {
                    // We won the race, now shift down
                    for (int j = actual_topk - 1; j > k; j--) {
                        shared_topk_vals[j] = shared_topk_vals[j - 1];
                        shared_topk_idx[j] = shared_topk_idx[j - 1];
                    }
                    shared_topk_vals[k] = score;
                    shared_topk_idx[k] = i;
                }
                break;
            }
        }
    }
    __syncthreads();

    // Convert local indices to global token indices and write output
    for (int i = tid; i < actual_topk; i += BLOCK_SIZE) {
        int local_idx = shared_topk_idx[i];
        if (local_idx >= 0) {
            int page_idx = local_idx / PAGE_SIZE;
            int offset = local_idx % PAGE_SIZE;
            int global_page_idx = block_ptr[page_idx];
            int global_token_idx = global_page_idx * PAGE_SIZE + offset;
            topk_indices[b * TOPK + i] = global_token_idx;
        }
    }
}

void launch_dsa_topk_indexer(
    const uint8_t* q_index_fp8,
    const uint8_t* k_index_cache_fp8,
    const float* weights,
    const int* seq_lens,
    const int* block_table,
    int* topk_indices,
    int batch_size,
    int num_pages,
    int max_num_pages,
    cudaStream_t stream
) {
    // Calculate shared memory size (for scores array)
    // Max seq_len can be up to max_num_pages * PAGE_SIZE
    int max_seq_len = max_num_pages * PAGE_SIZE;
    size_t shared_mem_size = max_seq_len * sizeof(float) + TOPK * sizeof(float) + TOPK * sizeof(int);

    dim3 grid(batch_size);
    dim3 block(BLOCK_SIZE);

    dsa_topk_indexer_kernel<<<grid, block, shared_mem_size, stream>>>(
        q_index_fp8,
        k_index_cache_fp8,
        weights,
        seq_lens,
        block_table,
        topk_indices,
        batch_size,
        num_pages,
        max_num_pages
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <stdexcept>
#include <vector>

std::tuple<torch::Tensor> run(
    torch::Tensor q_index_fp8,
    torch::Tensor k_index_cache_fp8,
    torch::Tensor weights,
    torch::Tensor seq_lens,
    torch::Tensor block_table
) {
    // Validate inputs are on CUDA device
    TORCH_CHECK(q_index_fp8.device().is_cuda(), "q_index_fp8 must be on CUDA device");
    TORCH_CHECK(k_index_cache_fp8.device().is_cuda(), "k_index_cache_fp8 must be on CUDA device");
    TORCH_CHECK(weights.device().is_cuda(), "weights must be on CUDA device");
    TORCH_CHECK(seq_lens.device().is_cuda(), "seq_lens must be on CUDA device");
    TORCH_CHECK(block_table.device().is_cuda(), "block_table must be on CUDA device");

    // Validate tensor shapes
    auto q_sizes = q_index_fp8.sizes();
    TORCH_CHECK(q_sizes.size() == 3, "q_index_fp8 must be 3D tensor");
    TORCH_CHECK(q_sizes[1] == NUM_INDEX_HEADS, "q_index_fp8 num_index_heads must be 64");
    TORCH_CHECK(q_sizes[2] == INDEX_HEAD_DIM, "q_index_fp8 index_head_dim must be 128");

    auto k_sizes = k_index_cache_fp8.sizes();
    TORCH_CHECK(k_sizes.size() == 4, "k_index_cache_fp8 must be 4D tensor");
    TORCH_CHECK(k_sizes[1] == PAGE_SIZE, "k_index_cache_fp8 page_size must be 64");
    TORCH_CHECK(k_sizes[3] == HEAD_DIM_WITH_SCALE, "k_index_cache_fp8 head_dim_with_scale must be 132");

    auto w_sizes = weights.sizes();
    TORCH_CHECK(w_sizes.size() == 2, "weights must be 2D tensor");
    TORCH_CHECK(w_sizes[1] == NUM_INDEX_HEADS, "weights num_index_heads must be 64");

    auto sl_sizes = seq_lens.sizes();
    TORCH_CHECK(sl_sizes.size() == 1, "seq_lens must be 1D tensor");

    auto bt_sizes = block_table.sizes();
    TORCH_CHECK(bt_sizes.size() == 2, "block_table must be 2D tensor");
    TORCH_CHECK(bt_sizes[0] == q_sizes[0], "batch_size mismatch between q_index_fp8 and block_table");

    // Validate dtypes
    TORCH_CHECK(q_index_fp8.dtype() == at::kFloat8_e4m3fn, "q_index_fp8 must be FP8");
    TORCH_CHECK(k_index_cache_fp8.dtype() == at::kChar, "k_index_cache_fp8 must be INT8");
    TORCH_CHECK(weights.dtype() == at::kFloat, "weights must be FLOAT32");
    TORCH_CHECK(seq_lens.dtype() == at::kInt, "seq_lens must be INT32");
    TORCH_CHECK(block_table.dtype() == at::kInt, "block_table must be INT32");

    // Extract dimensions
    int batch_size = q_sizes[0];
    int num_pages = k_sizes[0];
    int max_num_pages = bt_sizes[1];

    // Create output tensor
    auto topk_indices = torch::full(
        {batch_size, TOPK},
        -1,
        torch::dtype(at::kInt).device(q_index_fp8.device())
    );

    // Get raw pointers - use uint8_t for FP8 to avoid linking issues
    const uint8_t* q_ptr = reinterpret_cast<const uint8_t*>(q_index_fp8.data_ptr<uint8_t>());
    const uint8_t* k_ptr = k_index_cache_fp8.data_ptr<uint8_t>();
    const float* w_ptr = weights.data_ptr<float>();
    const int* sl_ptr = seq_lens.data_ptr<int>();
    const int* bt_ptr = block_table.data_ptr<int>();
    int* topk_ptr = topk_indices.data_ptr<int>();

    // Get CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    launch_dsa_topk_indexer(
        q_ptr,
        k_ptr,
        w_ptr,
        sl_ptr,
        bt_ptr,
        topk_ptr,
        batch_size,
        num_pages,
        max_num_pages,
        stream
    );

    // Check for errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error: ") + cudaGetErrorString(err));
    }

    return std::make_tuple(topk_indices);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "DSA Top-K Indexer kernel for A800 GPU");
}
